// UUID Generator using cryptographically secure random number generation
class UuidGenerator {
  static final Random _secureRandom = Random.secure();

  /// Generates a UUID v4 (random) compliant string
  static String generateV4() {
    final bytes = List<int>.generate(16, (_) => _secureRandom.nextInt(256));

    // Set version to 4 (0100 in binary) - byte 6
    bytes[6] = (bytes[6] & 0x0F) | 0x40;

    // Set variant to RFC 4122 (10xx in binary) - byte 8
    bytes[8] = (bytes[8] & 0x3F) | 0x80;

    return _formatUuid(bytes);
  }

  /// Generates a UUID v1-like (time-based) with secure random node
  static String generateTimeBased() {
    final now = DateTime.now().toUtc();
    final timestamp = now.microsecondsSinceEpoch;

    // Convert timestamp to bytes (8 bytes)
    final timeBytes = <int>[];
    var ts = timestamp;
    for (var i = 0; i < 8; i++) {
      timeBytes.add(ts & 0xFF);
      ts >>= 8;
    }

    // Generate secure random clock sequence and node
    final randomBytes = List<int>.generate(8, (_) => _secureRandom.nextInt(256));

    final bytes = <int>[
      // time_low (4 bytes)
      timeBytes[0], timeBytes[1], timeBytes[2], timeBytes[3],
      // time_mid (2 bytes)
      timeBytes[4], timeBytes[5],
      // time_hi_and_version (2 bytes) - version 1
      (timeBytes[6] & 0x0F) | 0x10, timeBytes[7],
      // clock_seq_hi_and_reserved - variant RFC 4122
      (randomBytes[0] & 0x3F) | 0x80, randomBytes[1],
      // node (6 bytes) - secure random
      randomBytes[2], randomBytes[3], randomBytes[4],
      randomBytes[5], randomBytes[6], randomBytes[7],
    ];

    return _formatUuid(bytes);
  }

  /// Generates a UUID v5-like (name-based with SHA-like hash using secure mixing)
  static String generateNameBased(String namespace, String name) {
    final input = '$namespace:$name';
    final inputBytes = utf8.encode(input);

    // Simple but secure hash mixing using multiple rounds
    final hash = _secureHash(inputBytes);

    // Take first 16 bytes
    final bytes = hash.sublist(0, 16);

    // Set version to 5 (0101 in binary)
    bytes[6] = (bytes[6] & 0x0F) | 0x50;

    // Set variant to RFC 4122
    bytes[8] = (bytes[8] & 0x3F) | 0x80;

    return _formatUuid(bytes);
  }

  /// Generates a compact ID (shorter, for display purposes)
  static String generateCompactId({int length = 12}) {
    const chars = 'ABCDEFGHIJKLMNOPQRSTUVWXYZabcdefghijklmnopqrstuvwxyz0123456789';
    return List.generate(length, (_) => chars[_secureRandom.nextInt(chars.length)]).join();
  }

  /// Generates a sortable UUID (timestamp prefix + random suffix)
  static String generateSortable() {
    final now = DateTime.now().toUtc();
    final timestamp = now.microsecondsSinceEpoch;

    // 12 hex chars for timestamp (48 bits)
    final timePart = timestamp.toRadixString(16).padLeft(12, '0');

    // 20 hex chars of secure random
    final randomPart = List.generate(10, (_) => _secureRandom.nextInt(256))
        .map((b) => b.toRadixString(16).padLeft(2, '0'))
        .join();

    final combined = timePart + randomPart;

    return '${combined.substring(0, 8)}-'
        '${combined.substring(8, 12)}-'
        '${combined.substring(12, 16)}-'
        '${combined.substring(16, 20)}-'
        '${combined.substring(20, 32)}';
  }

  /// Secure hash function using multiple mixing rounds (no external deps)
  static List<int> _secureHash(List<int> input) {
    // Initialize state with secure random seed
    final state = List<int>.generate(32, (i) => (i * 0x9E3779B9 + 0x6A09E667) & 0xFF);

    // Mix input into state
    for (var round = 0; round < 4; round++) {
      for (var i = 0; i < input.length; i++) {
        final idx = i % 32;
        state[idx] = (state[idx] ^ input[i]) & 0xFF;
        // Avalanche mixing
        state[(idx + 1) % 32] = (state[(idx + 1) % 32] + state[idx] * 31 + round) & 0xFF;
        state[(idx + 7) % 32] = (state[(idx + 7) % 32] ^ (state[idx] << 3)) & 0xFF;
        state[(idx + 13) % 32] = (state[(idx + 13) % 32] + (state[idx] >> 2) + i) & 0xFF;
      }

      // Additional diffusion
      for (var i = 0; i < 32; i++) {
        state[i] = (state[i] ^ state[(i + 16) % 32] ^ (round * 0x5A)) & 0xFF;
      }
    }

    return state;
  }

  static String _formatUuid(List<int> bytes) {
    final hex = bytes.map((b) => b.toRadixString(16).padLeft(2, '0')).join();
    return '${hex.substring(0, 8)}-'
        '${hex.substring(8, 12)}-'
        '${hex.substring(12, 16)}-'
        '${hex.substring(16, 20)}-'
        '${hex.substring(20, 32)}';
  }

  /// Validates a UUID string format
  static bool isValidUuid(String uuid) {
    final regex = RegExp(
      r'^[0-9a-f]{8}-[0-9a-f]{4}-[0-9a-f]{4}-[0-9a-f]{4}-[0-9a-f]{12}$',
      caseSensitive: false,
    );
    return regex.hasMatch(uuid);
  }

  /// Extracts version from a UUID string
  static int? getVersion(String uuid) {
    if (!isValidUuid(uuid)) return null;
    final versionChar = uuid.replaceAll('-', '')[12];
    return int.tryParse(versionChar, radix: 16);
  }
}

// Offline Data Entry Model
class OfflineDataEntry {
  final String id;
  final String title;
  final String content;
  final DateTime createdAt;
  final String uuidType;
  bool isSynced;

  OfflineDataEntry({
    required this.id,
    required this.title,
    required this.content,
    required this.createdAt,
    required this.uuidType,
    this.isSynced = false,
  });

  Map<String, dynamic> toJson() => {
        'id': id,
        'title': title,
        'content': content,
        'createdAt': createdAt.toIso8601String(),
        'uuidType': uuidType,
        'isSynced': isSynced,
      };
}

// Offline Sync Manager
class OfflineSyncManager {
  final List<OfflineDataEntry> _pendingEntries = [];
  final List<OfflineDataEntry> _syncedEntries = [];

  List<OfflineDataEntry> get pendingEntries => List.unmodifiable(_pendingEntries);
  List<OfflineDataEntry> get syncedEntries => List.unmodifiable(_syncedEntries);
  List<OfflineDataEntry> get allEntries => [..._pendingEntries, ..._syncedEntries];

  OfflineDataEntry createEntry({
    required String title,
    required String content,
    String uuidType = 'v4',
  }) {
    String id;
    switch (uuidType) {
      case 'v1':
        id = UuidGenerator.generateTimeBased();
        break;
      case 'v5':
        id = UuidGenerator.generateNameBased('offline-app', '$title:$content:${DateTime.now()}');
        break;
      case 'sortable':
        id = UuidGenerator.generateSortable();
        break;
      case 'compact':
        id = UuidGenerator.generateCompactId();
        break;
      case 'v4':
      default:
        id = UuidGenerator.generateV4();
        break;
    }

    final entry = OfflineDataEntry(
      id: id,
      title: title,
      content: content,
      createdAt: DateTime.now().toUtc(),
      uuidType: uuidType,
    );

    _pendingEntries.add(entry);
    return entry;
  }

  Future<int> simulateSync() async {
    // Simulate network delay
    await Future.delayed(const Duration(seconds: 2));

    int syncedCount = 0;
    final toSync = List<OfflineDataEntry>.from(_pendingEntries);

    for (final entry in toSync) {
      entry.isSynced = true;
      _pendingEntries.remove(entry);
      _syncedEntries.add(entry);
      syncedCount++;
    }

    return syncedCount;
  }

  void clearSynced() {
    _syncedEntries.clear();
  }
}

