// UUID Generator Tab Widget
class UuidGeneratorTab extends StatefulWidget {
  const UuidGeneratorTab({super.key});

  @override
  State<UuidGeneratorTab> createState() => _UuidGeneratorTabState();
}

class _UuidGeneratorTabState extends State<UuidGeneratorTab> {
  final List<_GeneratedUuid> _generatedUuids = [];
  String _selectedType = 'v4';
  final _namespaceController = TextEditingController(text: 'my-app');
  final _nameController = TextEditingController(text: 'entity');
  int _batchCount = 1;

  final Map<String, String> _uuidTypes = {
    'v4': 'UUID v4 (Random)',
    'v1': 'UUID v1 (Time-based)',
    'v5': 'UUID v5 (Name-based)',
    'sortable': 'Sortable UUID',
    'compact': 'Compact ID',
  };

  void _generate() {
    setState(() {
      for (var i = 0; i < _batchCount; i++) {
        String uuid;
        switch (_selectedType) {
          case 'v1':
            uuid = UuidGenerator.generateTimeBased();
            break;
          case 'v5':
            uuid = UuidGenerator.generateNameBased(
              _namespaceController.text,
              '${_nameController.text}:${DateTime.now().microsecondsSinceEpoch}:$i',
            );
            break;
          case 'sortable':
            uuid = UuidGenerator.generateSortable();
            break;
          case 'compact':
            uuid = UuidGenerator.generateCompactId();
            break;
          case 'v4':
          default:
            uuid = UuidGenerator.generateV4();
            break;
        }
        _generatedUuids.insert(
          0,
          _GeneratedUuid(
            uuid: uuid,
            type: _selectedType,
            timestamp: DateTime.now(),
          ),
        );
      }
    });
  }

  @override
  void dispose() {
    _namespaceController.dispose();
    _nameController.dispose();
    super.dispose();
  }

  @override
  Widget build(BuildContext context) {
    return Column(
      children: [
        // Controls
        Card(
          margin: const EdgeInsets.all(16),
          child: Padding(
            padding: const EdgeInsets.all(16),
            child: Column(
              crossAxisAlignment: CrossAxisAlignment.stretch,
              children: [
                // UUID Type Selector
                DropdownButtonFormField<String>(
                  value: _selectedType,
                  decoration: const InputDecoration(
                    labelText: 'UUID Type',
                    border: OutlineInputBorder(),
                    prefixIcon: Icon(Icons.category),
                  ),
                  items: _uuidTypes.entries
                      .map((e) => DropdownMenuItem(
                            value: e.key,
                            child: Text(e.value),
                          ))
                      .toList(),
                  onChanged: (value) => setState(() => _selectedType = value!),
                ),

                // Name-based fields
                if (_selectedType == 'v5') ...[
                  const SizedBox(height: 12),
                  Row(
                    children: [
                      Expanded(
                        child: TextField(
                          controller: _namespaceController,
                          decoration: const InputDecoration(
                            labelText: 'Namespace',
                            border: OutlineInputBorder(),
                            isDense: true,
                          ),
                        ),
                      ),
                      const SizedBox(width: 12),
                      Expanded(
                        child: TextField(
                          controller: _nameController,
                          decoration: const InputDecoration(
                            labelText: 'Name',
                            border: OutlineInputBorder(),
                            isDense: true,
                          ),
                        ),
                      ),
                    ],
                  ),
                ],

                const SizedBox(height: 12),

                // Batch count and generate button
                Row(
                  children: [
                    const Text('Count: '),
                    DropdownButton<int>(
                      value: _batchCount,
                      items: [1, 5, 10, 25, 50]
                          .map((n) => DropdownMenuItem(
                                value: n,
                                child: Text('$n'),
                              ))
                          .toList(),
                      onChanged: (v) => setState(() => _batchCount = v!),
                    ),
                    const Spacer(),
                    FilledButton.icon(
                      onPressed: _generate,
                      icon: const Icon(Icons.generating_tokens),
                      label: const Text('Generate'),
                    ),
                    const SizedBox(width: 8),
                    OutlinedButton(
                      onPressed: _generatedUuids.isEmpty
                          ? null
                          : () => setState(() => _generatedUuids.clear()),
                      child: const Text('Clear'),
                    ),
                  ],
                ),
              ],
            ),
          ),
        ),

        // Info chip
        if (_generatedUuids.isNotEmpty)
          Padding(
            padding: const EdgeInsets.symmetric(horizontal: 16),
            child: Row(
              children: [
                Chip(
                  avatar: const Icon(Icons.list, size: 18),
                  label: Text('${_generatedUuids.length} generated'),
                ),
                const Spacer(),
                TextButton.icon(
                  onPressed: () {
                    final allUuids = _generatedUuids.map((u) => u.uuid).join('\n');
                    Clipboard.setData(ClipboardData(text: allUuids));
                    ScaffoldMessenger.of(context).showSnackBar(
                      const SnackBar(
                        content: Text('All UUIDs copied to clipboard'),
                        duration: Duration(seconds: 1),
                      ),
                    );
                  },
                  icon: const Icon(Icons.copy_all, size: 18),
                  label: const Text('Copy All'),
                ),
              ],
            ),
          ),

        // Generated UUIDs List
        Expanded(
          child: _generatedUuids.isEmpty
              ? Center(
                  child: Column(
                    mainAxisAlignment: MainAxisAlignment.center,
                    children: [
                      Icon(Icons.fingerprint, size: 80, color: Colors.grey.withOpacity(0.3)),
                      const SizedBox(height: 16),
                      Text(
                        'Generate UUIDs above',
                        style: TextStyle(color: Colors.grey.shade500, fontSize: 16),
                      ),
                      const SizedBox(height: 4),
                      Text(
                        'Cryptographically secure random generation',
                        style: TextStyle(color: Colors.grey.shade400, fontSize: 12),
                      ),
                    ],
                  ),
                )
              : ListView.builder(
                  padding: const EdgeInsets.symmetric(horizontal: 16, vertical: 4),
                  itemCount: _generatedUuids.length,
                  itemBuilder: (context, index) {
                    final item = _generatedUuids[index];
                    final version = UuidGenerator.getVersion(item.uuid);
                    return Card(
                      child: InkWell(
                        onTap: () {
                          Clipboard.setData(ClipboardData(text: item.uuid));
                          ScaffoldMessenger.of(context).showSnackBar(
                            SnackBar(
                              content: Text('Copied: ${item.uuid}'),
                              duration: const Duration(seconds: 1),
                            ),
                          );
                        },
                        borderRadius: BorderRadius.circular(12),
                        child: Padding(
                          padding: const EdgeInsets.all(12),
                          child: Row(
                            children: [
                              CircleAvatar(
                                radius: 16,
                                child: Text(
                                  item.type.toUpperCase().substring(0, 2),
                                  style: const TextStyle(fontSize: 10, fontWeight: FontWeight.bold),
                                ),
                              ),
                              const SizedBox(width: 12),
                              Expanded(
                                child: Column(
                                  crossAxisAlignment: CrossAxisAlignment.start,
                                  children: [
                                    Text(
                                      item.uuid,
                                      style: TextStyle(
                                        fontFamily: 'monospace',
                                        fontSize: 13,
                                        fontWeight: FontWeight.w600,
                                        color: Theme.of(context).colorScheme.primary,
                                      ),
                                    ),
                                    const SizedBox(height: 2),
                                    Text(
                                      '${_uuidTypes[item.type]}${version != null ? ' • v$version' : ''} • ${_formatTime(item.timestamp)}',
                                      style: TextStyle(
                                        fontSize: 10,
                                        color: Colors.grey.shade600,
                                      ),
                                    ),
                                  ],
                                ),
                              ),
                              const Icon(Icons.copy, size: 16, color: Colors.grey),
                            ],
                          ),
                        ),
                      ),
                    );
                  },
                ),
        ),
      ],
    );
  }

  String _formatTime(DateTime dt) {
    return '${dt.hour.toString().padLeft(2, '0')}:'
        '${dt.minute.toString().padLeft(2, '0')}:'
        '${dt.second.toString().padLeft(2, '0')}.'
        '${dt.millisecond.toString().padLeft(3, '0')}';
  }
}

class _GeneratedUuid {
  final String uuid;
  final String type;
  final DateTime timestamp;

  _GeneratedUuid({
    required this.uuid,
    required this.type,
    required this.timestamp,
  });
}

// Records Tab Widget
class RecordsTab extends StatefulWidget {
  final OfflineSyncManager syncManager;
  final VoidCallback onEntryCreated;

  const RecordsTab({
    super.key,
    required this.syncManager,
    required this.onEntryCreated,
  });

  @override
  State<RecordsTab> createState() => _RecordsTabState();
}

class _RecordsTabState extends State<RecordsTab> {
  final _titleController = TextEditingController();
  final _contentController = TextEditingController();
  String _recordUuidType = 'v4';

  final Map<String, String> _uuidTypes = {
    'v4': 'UUID v4 (Random)',
    'v1': 'UUID v1 (Time-based)',
    'v5': 'UUID v5 (Name-based)',
    'sortable': 'Sortable UUID',
    'compact': 'Compact ID',
  };

  @override
  void dispose() {
    _titleController.dispose();
    _contentController.dispose();
    super.dispose();
  }

  void _createRecord() {
    if (_titleController.text.isEmpty) {
      ScaffoldMessenger.of(context).showSnackBar(
        const SnackBar(
          content: Text('Please enter a title'),
          backgroundColor: Colors.red,
        ),
      );
      return;
    }

    final entry = widget.syncManager.createEntry(
      title: _titleController.text,
      content: _contentController.text,
      uuidType: _recordUuidType,
    );

    _titleController.clear();
    _contentController.clear();

    setState(() {});
    widget.onEntryCreated();

    ScaffoldMessenger.of(context).showSnackBar(
      SnackBar(
        content: Text('Created: ${entry.id}'),
        backgroundColor: Colors.green,
        action: SnackBarAction(
          label: 'Copy ID',
          textColor: Colors.white,
          onPressed: () {
            Clipboard.setData(ClipboardData(text: entry.id));
          },
        ),
      ),
    );
  }

  @override
  Widget build(BuildContext context) {
    return SingleChildScrollView(
      padding: const EdgeInsets.all(16),
      child: Column(
        crossAxisAlignment: CrossAxisAlignment.stretch,
        children: [
          // Create Record Card
          Card(
            child: Padding(
              padding: const EdgeInsets.all(16),
              child: Column(
                crossAxisAlignment: CrossAxisAlignment.stretch,
                children: [
                  Text(
                    'Create Offline Record',
                    style: Theme.of(context).textTheme.titleMedium?.copyWith(
                          fontWeight: FontWeight.bold,
                        ),
                  ),
                  const SizedBox(height: 16),
                  TextField(
                    controller: _titleController,
                    decoration: const InputDecoration(
                      labelText: 'Title',
                      border: OutlineInputBorder(),
                      prefixIcon: Icon(Icons.title),
                    ),
                  ),
                  const SizedBox(height: 12),
                  TextField(
                    controller: _contentController,
                    maxLines: 3,
                    decoration: const InputDecoration(
                      labelText: 'Content',
                      border: OutlineInputBorder(),
                      prefixIcon: Icon(Icons.description),
                      alignLabelWithHint: true,
                    ),
                  ),
                  const SizedBox(height: 12),
                  DropdownButtonFormField<String>(
                    value: _recordUuidType,
                    decoration: const InputDecoration(
                      labelText: 'ID Type',
                      border: OutlineInputBorder(),
                      prefixIcon: Icon(Icons.fingerprint),
                    ),
                    items: _uuidTypes.entries
                        .map((e) => DropdownMenuItem(
                              value: e.key,
                              child: Text(e.value),
                            ))
                        .toList(),
                    onChanged: (value) => setState(() => _recordUuidType = value!),
                  ),
                  const SizedBox(height: 16),
                  FilledButton.icon(
                    onPressed: _createRecord,
                    icon: const Icon(Icons.add),
                    label: const Text('Create Record (Offline)'),
                  ),
                ],
              ),
            ),
          ),

          const SizedBox(height: 16),

          // Quick Create Buttons
          Card(
            child: Padding(
              padding: const EdgeInsets.all(16),
              child: Column(
                crossAxisAlignment: CrossAxisAlignment.stretch,
                children: [
                  Text(
                    'Quick Create (Sample Records)',
                    style: Theme.of(context).textTheme.titleSmall?.copyWith(
                          fontWeight: FontWeight.bold,
                        ),
                  ),
                  const SizedBox(height: 12),
                  Wrap(
                    spacing: 8,
                    runSpacing: 8,
                    children: [
                      _quickCreateChip('Customer', Icons.person),
                      _quickCreateChip('Order', Icons.shopping_cart),
                      _quickCreateChip('Invoice', Icons.receipt),
                      _quickCreateChip('Task', Icons.task),
                      _quickCreateChip('Note', Icons.note),
                      _quickCreateChip('Photo', Icons.photo),
                    ],
                  ),
                ],
              ),
            ),
          ),

          const SizedBox(height: 16),

          // Collision Test Card
          Card(
            child: Padding(
              padding: const EdgeInsets.all(16),
              child: Column(
                crossAxisAlignment: CrossAxisAlignment.stretch,
                children: [
                  Text(
                    'Uniqueness Test',
                    style: Theme.of(context).textTheme.titleSmall?.copyWith(
                          fontWeight: FontWeight.bold,
                        ),
                  ),
                  const SizedBox(height: 8),
                  Text(
                    'Generate many UUIDs and verify no collisions occur.',
                    style: TextStyle(color: Colors.grey.shade600, fontSize: 13),
                  ),
                  const SizedBox(height: 12),
                  OutlinedButton.icon(
                    onPressed: () => _runCollisionTest(context),
                    icon: const Icon(Icons.science),
                    label: const Text('Run Collision Test (1000 UUIDs)'),
                  ),
                ],
              ),
            ),
          ),
        ],
      ),
    );
  }

  Widget _quickCreateChip(String label, IconData icon) {
    return ActionChip(
      avatar: Icon(icon, size: 18),
      label: Text(label),
      onPressed: () {
        final entry = widget.syncManager.createEntry(
          title: '$label ${DateTime.now().millisecondsSinceEpoch % 10000}',
          content: 'Auto-generated $label record',
          uuidType: _recordUuidType,
        );
        setState(() {});
        widget.onEntryCreated();
        ScaffoldMessenger.of(context).showSnackBar(
          SnackBar(
            content: Text('Created $label: ${entry.id}'),
            duration: const Duration(seconds: 1),
          ),
        );
      },
    );
  }

  void _runCollisionTest(BuildContext context) {
    final uuids = <String>{};
    const count = 1000;
    final stopwatch = Stopwatch()..start();

    for (var i = 0; i < count; i++) {
      uuids.add(UuidGenerator.generateV4());
    }

    stopwatch.stop();

    final hasCollisions = uuids.length != count;

    showDialog(
      context: context,
      builder: (ctx) => AlertDialog(
        icon: Icon(
          hasCollisions ? Icons.warning : Icons.check_circle,
          color: hasCollisions ? Colors.red : Colors.green,
          size: 48,
        ),
        title: Text(hasCollisions ? 'Collisions Detected!' : 'No Collisions!'),
        content: Column(
          mainAxisSize: MainAxisSize.min,
          children: [
            Text('Generated: $count UUIDs'),
            Text('Unique: ${uuids.length}'),
            Text('Time: ${stopwatch.elapsedMilliseconds}ms'),
            Text('Rate: ${(count / stopwatch.elapsedMilliseconds * 1000).toStringAsFixed(0)} UUIDs/sec'),
            const SizedBox(height: 12),
            Text(
              'Sample: ${uuids.first}',
              style: const TextStyle(fontFamily: 'monospace', fontSize: 11),
            ),
          ],
        ),
        actions: [
          TextButton(
            onPressed: () => Navigator.pop(ctx),
            child: const Text('OK'),
          ),
        ],
      ),
    );
  }
}